import React, { useState, useEffect, useRef } from 'react'
import './css_comp/seat_selection.css'
import { useNavigate } from 'react-router-dom'
export default function Seat_selection(props) {

  const seat = []
  const [booked, setBooked] = useState([18, 19, 30])
  const [selected, setSelected] = useState([])
  const compartment = props.compartment
  const [sortedCompartment, setSortedCompartment] = useState([]);
  const [currentCompartment,setCurrentCompartment]=useState()
  const [selected_compartment,setSelected_Compartment]=useState()

  const roww=useRef()


  useEffect(()=>{

    compartment.sort((item1,item2)=>(item1.remaining_seat<item2.remaining_seat)? 1:-1)
    setCurrentCompartment(compartment[0])
    setSelected_Compartment(compartment[0]?.compartment_id)
    console.log("sorteddd",selected_compartment)
    roww.current=compartment[0]
    // const row = selected_compartment?(selected_compartment?.total_seat) / column:0
    // const row = compartment[0].total_seat / column
    // console.log("sorted",compartment)
    console.log("from useRef",roww.current)


  },[compartment])
  const column = 5
  // console.log("sorteddd after useEffect",selected_compartment)
  
  const row =(roww.current?.total_seat) / column
  





  const navigate = useNavigate()
  let count = 1
  useEffect(() => {
    // console.log("update", booked)
  }, [booked])
  const handleBooked = (seatnumber) => {
    if (!selected.includes(seatnumber)) {
      setSelected((prevValue) => [...prevValue, seatnumber])

    } else {
      const newBooked = selected.filter((item) => item != seatnumber)
      setSelected(newBooked)
    }
  }

  for (let i = 0; i < row; i++) {
    const roww = []
    for (let j = 0; j < column + 1; j++) {
      if (j == 2) {
        roww.push(
          <div id="space" key={`${i}-${j}`}>

          </div>
        )
      } else {
        const currenCount = count
        if (booked.find((i) => i == count)) {
          roww.push(<div id='seat-booked' key={currenCount}>
            {count}
          </div>)
        } else if (selected.find((i) => i == currenCount)) {

          roww.push(<div id='seat-selected' onClick={() => handleBooked(currenCount)} key={currenCount}>
            {count}
          </div>)

        }


        else {
          roww.push(<div id='seat' onClick={() => handleBooked(currenCount)} key={currenCount}>
            {count}
          </div>)
        }

        count++
      }


    }
    seat.push(roww)

  }
  const Change_Compartment=(e)=>{
    const key_value=e.target.value
    const choosen_compartment=compartment.filter((item)=>item.compartment_id==key_value)
    // const item=e.target.value
    console.log(choosen_compartment[0].compartment_name)
    roww.current=choosen_compartment
    console.log(roww)
   

  }




  return (
    <>
      <div id='select_show'>
        <div id='caution'>Choose your seat(s)** Maximum 4 seats can be booked at a time.</div><hr />
        <div id='caution'><p>To know seat number(s), rest the cursor on your desired seat(s). Click on it to select or deselect.</p></div>

        <section className='parent'>

          <div className='left-child'>

            <h2>Select Coach</h2>
            <select name="" value={roww} onChange={Change_Compartment} id="select-coach" >
              {/* <option value="">Choose Compertment </option> */}
              {compartment.map((item) => (
                <option key={item.compartment_id} value={item.compartment_id}>{item.compartment_name}-{item.remaining_seat}</option>
              ))}
            </select>

            <div className="seat-status">
              <div className='available'>
                <p>Available</p>
                <div id='box'>

                </div>
              </div>
              <div className='available' id='booked'>
                <p>Booked</p>
                <div id='box'>

                </div>
              </div>
              <div className='available' id='selected'>
                <p>Selected</p>
                <div id='box'>

                </div>
              </div>

            </div>


            <div className="seat-choose">
              {seat.map((item, index) => (
                <div id='row'>
                  {item.map((element, index) => (
                    element
                  ))}
                </div>

              ))}

            </div>


          </div>

          <div className="right-child">

            <h2>Seat Details</h2>
            <div id='ticket-details'>
              <p>Class</p>
              <p>Seats</p>
              <p>Fare</p>
            </div>
            <div id='tickets'>
              here tickets
            </div>

            <div id='Total-amount'>
              <h3>Total: ৳ 0 </h3>
            </div>

            <div id='btn-purchase'><button onClick={() => navigate('/passangerinfo')} id='btn-continue-purchase'>CONTINUE PURCHASE</button></div>

          </div>

        </section>
      </div>

    </>
  )
}
